def range_summary(nums):
    if not nums:
        return ''

    runs = [(nums[0], nums[0])]
    for n in nums[1:]:
        if n == runs[-1][-1]+1:
            runs[-1][-1] = n
        else:
            runs.append((n, n))

    result = ', '.join(str(start) if start == end else f'{start}-{end}' for start, end in runs)
    return result
